import React from "react";

function MannaFoodsPayModal({ open, amount, ownerName, playerName, canAfford, onPay, onTrade, onClose }) {
  if (!open) return null;
  return (
    <div style={{ position: "fixed", top: 0, left: 0, width: "100vw", height: "100vh", background: "rgba(0,0,0,0.5)", zIndex: 1000, display: "flex", alignItems: "center", justifyContent: "center" }}>
      <div style={{ background: "#fff", borderRadius: 12, padding: 32, maxWidth: 420, boxShadow: "0 2px 16px #0003", textAlign: "center" }}>
        <h2>Mazel Tov on your wedding!</h2>
        <p>You need to pay <b>${amount}</b> for the banquet.</p>
        <p><b>{ownerName}</b> did a big mitzvah paying Manna Foods to cover the cost of an entire Banquet for a poor family.<br/>
        Now Manna Foods from Heaven pays them for every wedding.<br/>
        The money you pay is also a mitzva and will go into the Tzdaka fund.<br/>
        And a gift of <b>500 Zchut</b> to you.</p>
        {canAfford ? (
          <button style={{ margin: 8, padding: "8px 24px", background: "#4caf50", color: "#fff", border: "none", borderRadius: 6, fontWeight: "bold", fontSize: 16, cursor: "pointer" }} onClick={onPay}>Pay</button>
        ) : (
          <button style={{ margin: 8, padding: "8px 24px", background: "#f44336", color: "#fff", border: "none", borderRadius: 6, fontWeight: "bold", fontSize: 16, cursor: "pointer" }} onClick={onTrade}>Trade / Resolve</button>
        )}
        <button style={{ margin: 8, padding: "8px 24px", background: "#888", color: "#fff", border: "none", borderRadius: 6, fontWeight: "bold", fontSize: 16, cursor: "pointer" }} onClick={onClose}>Cancel</button>
      </div>
    </div>
  );
}

export default MannaFoodsPayModal;
